args.query:
WITH mx AS (
  SELECT 'SPY' AS Symbol, MAX("Adj Close") AS max_adj_close FROM "SPY" WHERE "Date" BETWEEN '2015-01-01' AND '2015-12-31'
  UNION ALL
  SELECT 'DIA' AS Symbol, MAX("Adj Close") AS max_adj_close FROM "DIA" WHERE "Date" BETWEEN '2015-01-01' AND '2015-12-31'
)
SELECT * FROM mx;

